anged));    /// <summary>    /// 标识 IsPinned 依赖属性.    /// </summary>    public static readonly DependencyProperty IsPinnedProperty =        DependencyProperty.Register("IsPinned", typeof(bool), typeof(BgTabItem), new PropertyMetadata(false, OnIsPinnedPropertyChanged));    /// <summary>    /// 标识 PinButtonVisibility 依赖属性.    /// </summary>    public static readonly DependencyProperty PinButtonVisibilityProperty =        DependencyProperty.Register("PinButtonVisibility", typeof(Visibility), typeof(BgTabItem), new PropertyMetadata(Visibility.Collapsed));    /// <summary>    /// 标识 CloseButtonVisibility 依赖属性.    /// </summary>    public static readonly DependencyProperty CloseButtonVisibilityProperty =        DependencyProperty.Register("CloseButtonVisibility", typeof(Visibility), typeof(BgTabItem), new PropertyMetadata(Visibility.Collapsed));    /// <summary>    /// 标识 LeftTemplate 依赖属性.    /// </summary>    public static readonly DependencyProperty LeftTemplateProperty =        DependencyProperty.Register("LeftTemplate", typeof(ControlTemplate), typeof(BgTabItem), new PropertyMetadata(OnLeftTemplateChanged));    /// <summary>    /// 标识 RightTemplate 依赖属性.    /// </summary>    public static readonly DependencyProperty RightTemplateProperty =        DependencyProperty.Register("RightTemplate", typeof(ControlTemplate), typeof(BgTabItem), new PropertyMetadata(OnRightTemplateChanged));    /// <summary>    /// 标识 TopTemplate 依赖属性.    /// </summary>    public static readonly DependencyProperty TopTemplateProperty =        DependencyProperty.Register("TopTemplate", typeof(ControlTemplate), typeof(BgTabItem), new PropertyMetadata(OnTopTemplateChanged));    /// <summary>    /// 标识 BottomTemplate 依赖属性.    /// </summary>    public static readonly DependencyProperty BottomTemplateProperty =        DependencyProperty.Register("BottomTemplate", typeof(ControlTemplate), typeof(BgTabItem), new PropertyMetadata(OnBottomTemplateChanged));    /// <summary>    /// 标识 DropDownContent 依赖属性.    /// </summary>    public static readonly DependencyProperty DropDownContentProperty =        DependencyProperty.Register("DropDownContent", typeof(object), typeof(BgTabItem), null);    /// <summary>    /// 标识 DropDownContentTemplate 依赖属性.    /// </summary>    public static readonly DependencyProperty DropDownContentTemplateProperty =        DependencyProperty.Register("DropDownContentTemplate", typeof(DataTemplate), typeof(BgTabItem), null);    /// <summary>    /// 标识 DropDownContentTemplateSelector 依赖属性.    /// </summary>    public static readonly DependencyProperty DropDownContentTemplateSelectorProperty =        DependencyProperty.Register("DropDownContentTemplateSelector", typeof(DataTemplateSelector), typeof(BgTabItem), null);    /// <summary>    /// 标识 HeaderForeground 依赖属性.    /// </summary>    public static readonly DependencyProperty HeaderForegroundProperty =        DependencyProperty.Register("HeaderForeground", typeof(Brush), typeof(BgTabItem), null);    /// <summary>    /// 标识 IsDragDisabled 依赖属性.    /// </summary>    public static readonly DependencyProperty IsDragDisabledProperty =        DependencyProperty.Register("IsDragDisabled", typeof(bool), typeof(BgTabItem), new PropertyMetadata(false));    /// <summary>    /// 标识 TabStripPlacement 只读依赖属性的 Key.    /// </summary>    private static readonly DependencyPropertyKey TabStripPlacementPropertyKey =        DependencyProperty.RegisterReadOnly("TabStripPlacement", typeof(Dock), typeof(BgTabItem), new PropertyMetadata(OnTabStripPlacementChanged));    /// <summary>    /// 标识 TabOrientation 只读依赖属性的 Key.    /// </summary>    private static readonly DependencyPropertyKey TabOrientationPropertyKey =        DependencyProperty.RegisterReadOnly("TabOrientation", typeof(Orientation), typeof(BgTabItem), new PropertyMetadata(Orientation.Horizontal, OnTabOrientationChanged));    /// <summary>    /// 标识 TabStripPlacement 依赖属性.    /// </summary>    public static readonly DependencyProperty TabStripPlacementProperty = TabStripPlacementPropertyKey.DependencyProperty;    /// <summary>    /// 标识 TabOrientation 依赖属性.    /// </summary>    public static readonly DependencyProperty TabOrientationProperty = TabOrientationPropertyKey.DependencyProperty;    /// <summary>    /// 标识 IsSelected 依赖属性.    /// </summary>    public static readonly DependencyProperty IsSelectedProperty = Selector.IsSelectedProperty.AddOwner(typeof(BgTabItem), new FrameworkPropertyMetadata(OnIsSelectedPropertyChanged));    /// <summary>    /// 内部状态标志.    /// </summary>    private StateFlags stateFlags = new StateFlags();    /// <summary>    /// 鼠标是否位于标题上.    /// </summary>    private bool isMouseOverHeader;    /// <summary>    /// 标题选项卡内容呈现器.    /// </summary>    private TabItemContentPresenter? headerTabItemPresenter;    /// <summary>    /// 标题内容呈现器.    /// </summary>    private ContentPresenter? headerContentPresenter;    /// <summary>    /// 标题包装器元素.    /// </summary>    private FrameworkElement? headerWrapperElement;    /// <summary>    /// Initializes static members of the <see cref="BgTabItem"/> class.    /// </summary>    static BgTabItem()    {        // 覆盖默认样式键.        DefaultStyleKeyProperty.OverrideMetadata(            typeof(BgTabItem),            new FrameworkPropertyMetadata(typeof(BgTabItem)));    }    /// <summary>    /// Initializes a new instance of the <see cref="BgTabItem"/> class.    /// </summary>    public BgTabItem()    {        // 绑定事件处理程序.        this.IsEnabledChanged += this.OnIsEnabledChanged;        this.Loaded += this.OnLoaded;    }    /// <summary>    /// Gets 选项卡条的放置位置.    /// </summary>    [Browsable(false)]    public virtual Dock TabStripPlacement => (Dock)this.GetValue(TabStripPlacementProperty);    /// <summary>    /// Gets 选项卡的方向.    /// </summary>    [Browsable(false)]    public virtual Orientation TabOrientation => (Orientation)this.GetValue(TabOrientationProperty);    /// <summary>    /// Gets or sets a value indicating whether 选项卡项是否被选中.    /// </summary>    public bool IsSelected    {        get => (bool)this.GetValue(IsSelectedProperty);        set => this.SetValue(IsSelectedProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否禁用拖拽.    /// </summary>    public bool IsDragDisabled    {        get => (bool)this.GetValue(IsDragDisabledProperty);        set => this.SetValue(IsDragDisabledProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否在此项处换行.    /// </summary>    public virtual bool IsBreak    {        get => (bool)this.GetValue(IsBreakProperty);        set => this.SetValue(IsBreakProperty, value);    }    /// <summary>    /// Gets or sets a value indicating whether 是否已固定.    /// </summary>    public bool IsPinned    {        get => (bool)this.GetValue(IsPinnedProperty);        set => this.SetValue(IsPinnedProperty, value);    }    /// <summary>    /// Gets or sets 固定按钮的可见性.    /// </summary>    public Visibility PinButtonVisibility    {        get => (Visibility)this.GetValue(PinButtonVisibilityProperty);        set => this.SetValue(PinButtonVisibilityProperty, value);    }    /// <summary>    /// Gets or sets 关闭按钮的可见性.    /// </summary>    public Visibility CloseButtonVisibility    {        get => (Visibility)this.GetValue(CloseButtonVisibilityProperty);        set => this.SetValue(CloseButtonVisibilityProperty, value);    }    /// <summary>    /// Gets or sets 左侧模板.    /// </summary>    public virtual ControlTemplate LeftTemplate    {        get => (ControlTemplate)this.GetValue(LeftTemplateProperty);        set => this.SetValue(LeftTemplateProperty, value);    }    /// <summary>    /// Gets or sets 右侧模板.    /// </summary>    public virtual ControlTemplate RightTemplate    {        get => (ControlTemplate)this.GetValue(RightTemplateProperty);        set => this.SetValue(RightTemplateProperty, value);    }    /// <summary>    /// Gets or sets 顶部模板.    /// </summary>    public virtual ControlTemplate TopTemplate    {        get => (ControlTemplate)this.GetValue(TopTemplateProperty);        set => this.SetValue(TopTemplateProperty, value);    }    /// <summary>    /// Gets or sets 底部模板.    /// </summary>    public virtual ControlTemplate BottomTemplate    {        get => (ControlTemplate)this.GetValue(BottomTemplateProperty);        set => this.SetValue(BottomTemplateProperty, value);    }    /// <summary>    /// Gets or sets 下拉内容.    /// </summary>    public object DropDownContent    {        get => this.GetValue(DropDownContentProperty);        set => this.SetValue(DropDownContentProperty, value);    }    /// <summary>    /// Gets or sets 下拉内容模板.    /// </summary>    public DataTemplate DropDownContentTemplate    {        get => (DataTemplate)this.GetValue(DropDownContentTemplateProperty);        set => this.SetValue(DropDownContentTemplateProperty, value);    }    /// <summary>    /// Gets or sets 下拉内容模板选择器.    /// </summary>    public DataTemplateSelector DropDownContentTemplateSelector    {        get => (DataTemplateSelector)this.GetValue(DropDownContentTemplateSelectorProperty);        set => this.SetValue(DropDownContentTemplateSelectorProperty, value);    }    /// <summary>    /// Gets or sets 标题前景色.    /// </summary>    public Brush HeaderForeground    {        get => (Brush)this.GetValue(HeaderForegroundProperty);        set => this.SetValue(HeaderForegroundProperty, value);    }    /// <summary>    /// Gets 所属的 BgTabControl 容器.    /// </summary>    internal BgTabControl? Owner => ItemsControl.ItemsControlFromItemContainer(this) as BgTabControl;    /// <summary>    /// Gets a value indicating whether 实际上是否已固定.    /// </summary>    internal bool IsActuallyPinned    {        get        {            // 检查固定属性及所有者容器状态.            if (this.IsPinned && this.Owner != null)            {                return this.Owner.PinnedItems.Contains(this);            }            return false;        }    }    /// <summary>    /// Gets or sets a value indicating whether 是否正在内部更改固定状态.    /// </summary>    internal bool IsPinnedChangingInternally { get; set; }    /// <summary>    /// Gets or sets a value indicating whether 是否正在被拖拽.    /// </summary>    internal bool IsBeingDragged { get; set; }    /// <summary>    /// Gets a value indicating whether 是否拥有所有者容器.    /// </summary>    private bool HasOwner => this.Owner != null;    /// <summary>    /// Gets 状态标志.    /// </summary>    private StateFlags Flags => this.stateFlags;    /// <summary>    /// Gets 实现接口的控件引用.    /// </summary>    Control ITabItem.Control => this;    /// <summary>    /// Gets 标题包装器元素.    /// </summary>    internal FrameworkElement? HeaderWrapper => this.headerWrapperElement;    /// <summary>    /// 更新选项卡条位置.    /// </summary>    /// <param name="value">位置停靠值.</param>    void ITabItem.UpdateTabStripPlacement(Dock value)    {        // 更新只读属性 Key.        this.SetValue(TabStripPlacementPropertyKey, value);    }    /// <summary>    /// 设置选项卡方向.    /// </summary>    /// <param name="value">方向值.</param>    void ITabItem.SetTabOrientation(Orientation value)    {        // 更新只读属性 Key.        this.SetValue(TabOrientationPropertyKey, value);    }    /// <summary>    /// 更新标题呈现器的内容.    /// </summary>    void ITabItem.UpdateHeaderPresenterContent()    {        // 同步 Header 到内容呈现器.        if (this.headerContentPresenter != null)        {            this.headerContentPresenter.Content = this.Header;        }    }    /// <summary>    /// 内部设置固定状态.    /// </summary>    /// <param name="pin">是否固定.</param>    internal void SetIsPinInternally(bool pin)    {        this.IsPinnedChangingInternally = true;        this.IsPinned = pin;        this.IsPinnedChangingInternally = false;    }    /// <summary>    /// 应用模板逻辑.    /// </summary>    public override void OnApplyTemplate()    {        base.OnApplyTemplate();        // 重置旧的内容呈现器内容.        if (this.headerContentPresenter != null)        {            this.headerContentPresenter.Content = null;        }        // 获取模板中的关键组件.        this.headerTabItemPresenter = this.GetTemplateChild("HeaderElement") as TabItemContentPresenter;        this.headerContentPresenter = this.GetTemplateChild("HeaderElement") as ContentPresenter;        ((ITabItem)this).UpdateHeaderPresenterContent();        this.Flags.HasPresenter = this.headerTabItemPresenter != null;        // 处理旧包装器的事件解绑.        if (this.headerWrapperElement != null)        {            this.headerWrapperElement.MouseLeftButtonDown -= this.OnHeaderMouseLeftButtonDown;            this.headerWrapperElement.MouseLeftButtonUp -= this.OnHeaderMouseLeftButtonUp;            this.headerWrapperElement.MouseEnter -= this.OnHeaderMouseEnter;            this.headerWrapperElement.MouseLeave -= this.OnHeaderMouseLeave;            this.headerWrapperElement.MouseDown -= this.OnHeaderMouseDown;            this.headerWrapperElement.RemoveHandler(AccessKeyManager.AccessKeyPressedEvent, new AccessKeyPressedEventHandler(this.OnAccessKeyPressed));        }        // 查找并绑定新包装器.        this.headerWrapperElement = this.GetTemplateChild("wrapper") as FrameworkElement;        if (this.headerWrapperElement != null)        {            this.headerWrapperElement.AddHandler(UIElement.MouseLeftButtonDownEvent, new MouseButtonEventHandler(this.OnHeaderMouseLeftButtonDown), true);            this.headerWrapperElement.AddHandler(UIElement.MouseLeftButtonUpEvent, new MouseButtonEventHandler(this.OnHeaderMouseLeftButtonUp), true);            this.headerWrapperElement.AddHandler(UIElement.MouseEnterEvent, new MouseEventHandler(this.OnHeaderMouseEnter), true);            this.headerWrapperElement.AddHandler(UIElement.MouseLeaveEvent, new MouseEventHandler(this.OnHeaderMouseLeave), true);            this.headerWrapperElement.AddHandler(UIElement.MouseDownEvent, new MouseButtonEventHandler(this.OnHeaderMouseDown), true);            this.headerWrapperElement.AddHandler(AccessKeyManager.AccessKeyPressedEvent, new AccessKeyPressedEventHandler(this.OnAccessKeyPressed));        }        // 配置呈现器的所有者.        if (this.Flags.HasPresenter && this.headerTabItemPresenter != null)        {            this.headerTabItemPresenter.TabItemOwner = this;        }        // 初始化视觉状态与导航模式.        this.ChangeVisualStateLocal();        this.SetNavigationMode(KeyboardNavigationMode.Local);        this.Flags.IsLoaded = true;    }    /// <summary>    /// 创建自动化对等体.    /// </summary>    /// <returns>自动化对等体实例.</returns>    protected override AutomationPeer? OnCreateAutomationPeer()    {        // 根据自动化模式返回对应的 Peer.        if (AutomationManager.AutomationMode == AutomationMode.Disabled)        {            return null;        }        if (AutomationManager.AutomationMode == AutomationMode.FrameworkOnly)        {            return base.OnCreateAutomationPeer();        }        return new BgControls.Windows.Automation.Peers.TabItemWrapperAutomationPeer(this);    }    /// <summary>    /// 控件初始化逻辑.    /// </summary>    /// <param name="e">事件参数.</param>    protected override void OnInitialized(EventArgs e)    {        base.OnInitialized(e);    }    /// <summary>    /// 鼠标进入逻辑.    /// </summary>    /// <param name="e">鼠标参数.</param>    protected override void OnMouseEnter(MouseEventArgs e)    {        base.OnMouseEnter(e);        this.ChangeVisualStateLocal();    }    /// <summary>    /// 鼠标离开逻辑.    /// </summary>    /// <param name="e">鼠标参数.</param>    protected override void OnMouseLeave(MouseEventArgs e)    {        base.OnMouseLeave(e);        this.ChangeVisualStateLocal();    }    /// <summary>    /// 按键按下逻辑.    /// </summary>    /// <param name="e">按键参数.</param>    protected override void OnKeyDown(KeyEventArgs e)    {        base.OnKeyDown(e);        // 如果有容器则交由容器处理按键.        if (this.HasOwner && this.Owner != null)        {            e.Handled = this.Owner.OnKeyDownInternal(e.Key);        }    }    /// <summary>    /// 内容变更逻辑.    /// </summary>    /// <param name="oldContent">旧内容.</param>    /// <param name="newContent">新内容.</param>    protected override void OnContentChanged(object oldContent, object newContent)    {        base.OnContentChanged(oldContent, newContent);        // 通知容器内容已更改.        if (this.HasOwner && this.IsSelected && this.Owner != null)        {            this.Owner.NotifyChildContentChanged();        }    }    /// <summary>    /// 测量逻辑.    /// </summary>    /// <param name="constraint">可用尺寸.</param>    /// <returns>测量尺寸.</returns>    protected override Size MeasureOverride(Size constraint)    {        // 强制刷新标题呈现器的测量.        if (this.Flags.HasPresenter && this.headerTabItemPresenter != null)        {            this.headerTabItemPresenter.InvalidateMeasure();        }        return base.MeasureOverride(constraint);    }    /// <summary>    /// 标题变更逻辑.    /// </summary>    /// <param name="oldHeader">旧标题.</param>    /// <param name="newHeader">新标题.</param>    protected override void OnHeaderChanged(object oldHeader, object newHeader)    {        base.OnHeaderChanged(oldHeader, newHeader);        ((ITabItem)this).UpdateHeaderPresenterContent();    }    /// <summary>    /// 获得焦点逻辑.    /// </summary>    /// <param name="e">路由参数.</param>    protected override void OnGotFocus(RoutedEventArgs e)    {        base.OnGotFocus(e);    }    /// <summary>    /// 失去焦点逻辑.    /// </summary>    /// <param name="e">路由参数.</param>    protected override void OnLostFocus(RoutedEventArgs e)    {        base.OnLostFocus(e);    }    /// <summary>    /// 选中时的处理.    /// </summary>    /// <param name="e">路由参数.</param>    public virtual void OnSelected(RoutedEventArgs e)    {    }    /// <summary>    /// 取消选中时的处理.    /// </summary>    /// <param name="e">路由参数.</param>    public virtual void OnUnselected(RoutedEventArgs e)    {    }    /// <summary>    /// 更新控件模板.    /// </summary>    protected internal void UpdateTemplate()    {        // 根据放置位置查找模板.        ControlTemplate? targetTemplate = this.FindTemplateFromPosition(this.TabStripPlacement);        if (targetTemplate != null)        {            this.Template = targetTemplate;            if (this.headerTabItemPresenter != null)            {                this.headerTabItemPresenter.ClearValue(ContentControl.ContentProperty);            }            if (this.Flags.IsLoaded)            {                this.ApplyTemplate();            }        }    }    /// <summary>    /// 切换视觉状态.    /// </summary>    /// <param name="useTransitions">是否使用过渡动画.</param>    protected internal virtual void ChangeVisualState(bool useTransitions)    {        // 焦点状态切换.        if (this.IsFocused)        {            this.GoToState(useTransitions, "Focused", "Unfocused");        }        else        {            this.GoToState(useTransitions, "Unfocused");        }        // 位置状态切换.        string placementStateName = this.TabOrientation.ToString() + this.TabStripPlacement.ToString();        this.GoToState(useTransitions, placementStateName);        // 交互状态切换.        if (!this.IsEnabled)        {            this.GoToState(useTransitions, "Disabled", "Normal");        }        else if (this.IsSelected && this.isMouseOverHeader)        {            this.GoToState(useTransitions, "SelectedMouseOver", "Selected", "MouseOver", "Normal");        }        else if (this.IsSelected)        {            this.GoToState(useTransitions, "Selected", "MouseOver", "Normal");        }        else if (this.isMouseOverHeader)        {            this.GoToState(useTransitions, "MouseOver", "Normal");        }        else        {            this.GoToState(useTransitions, "Normal");        }    }    /// <summary>    /// 控件加载完成回调.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    protected virtual void OnLoaded(object sender, RoutedEventArgs e)    {        // 处理选中逻辑通知.        if (this.HasOwner && this.IsSelected && this.Owner != null)        {            this.NotifyOwnerAboutChangedSelection(true);            this.Owner.NotifyChildContentChanged();        }        // 处理固定状态同步.        if (this.HasOwner && this.Owner != null && this.IsPinned && !this.IsActuallyPinned && !this.IsBeingDragged)        {            if (!this.Owner.IsPinnedPropertyChangedSuccessfull(this, true))            {                this.SetIsPinInternally(false);            }        }        this.IsBeingDragged = false;    }    /// <summary>    /// 标题区域鼠标左键按下.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    protected virtual void OnHeaderMouseLeftButtonDown(object sender, MouseButtonEventArgs e)    {        if (!this.HasOwner || this.Owner == null)        {            return;        }        this.Owner.IsUserInitiatedSelection = true;        if (this.IsEnabled && !e.Handled)        {            if (this.IsSelected)            {                this.Focus();            }            else            {                this.IsSelected = true;            }            e.Handled = true;        }        this.Owner.MarkItemForDragging(this);    }    /// <summary>    /// 标题区域鼠标左键弹起.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    protected virtual void OnHeaderMouseLeftButtonUp(object? sender, MouseButtonEventArgs e)    {        if (this.HasOwner && this.Owner != null)        {            this.Owner.IsUserInitiatedSelection = false;            this.Owner.MarkItemForDragging(null);        }    }    /// <summary>    /// 标题区域鼠标进入.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    protected virtual void OnHeaderMouseEnter(object? sender, MouseEventArgs e)    {        this.isMouseOverHeader = true;        this.ChangeVisualState(false);    }    /// <summary>    /// 标题区域鼠标离开.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    protected virtual void OnHeaderMouseLeave(object? sender, MouseEventArgs e)    {        this.isMouseOverHeader = false;        this.ChangeVisualState(false);    }    /// <summary>    /// 选中状态变更逻辑.    /// </summary>    /// <param name="oldValue">旧值.</param>    /// <param name="newValue">新值.</param>    protected virtual void OnIsSelectedChanged(bool oldValue, bool newValue)    {        this.NotifyOwnerAboutChangedSelection(newValue);        if (this.HasOwner && this.Owner != null)        {            AutomationPeer automationPeer = UIElementAutomationPeer.FromElement(this);            if (automationPeer != null && newValue)            {                automationPeer.ResetChildrenCache();            }            this.Owner.RaiseIsSelectedChangedAutomationEvent(this, newValue);        }        this.ChangeVisualStateLocal();    }    /// <summary>    /// 根据位置查找对应模板.    /// </summary>    /// <param name="position">停靠位置.</param>    /// <returns>控件模板.</returns>    protected virtual ControlTemplate? FindTemplateFromPosition(Dock position)    {        return position switch        {            Dock.Top => this.TopTemplate,            Dock.Bottom => this.BottomTemplate,            Dock.Left => this.LeftTemplate,            Dock.Right => this.RightTemplate,            _ => null,        };    }    /// <summary>    /// 设置导航模式.    /// </summary>    /// <param name="mode">导航模式值.</param>    protected void SetNavigationMode(KeyboardNavigationMode mode)    {        KeyboardNavigation.SetTabNavigation(this, mode);    }    /// <summary>    /// 处理标题区域鼠标按下（含中键）.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnHeaderMouseDown(object sender, MouseButtonEventArgs e)    {        // 响应鼠标中键关闭标签页.        if (e.ChangedButton == MouseButton.Middle && this.HasOwner && this.Owner != null && this.Owner.CloseTabsOnMouseMiddleButtonDown)        {            TabItemCommands.Close.Execute(null, this);        }    }    /// <summary>    /// 通知所有者关于选中的更改.    /// </summary>    /// <param name="isSelected">是否被选中.</param>    private void NotifyOwnerAboutChangedSelection(bool isSelected)    {        RoutedEventArgs selectionArgs = isSelected ?            new RoutedEventArgs(Selector.SelectedEvent, this) :            new RoutedEventArgs(Selector.UnselectedEvent, this);        this.RaiseEvent(selectionArgs);    }    /// <summary>    /// 启用状态变更回调.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnIsEnabledChanged(object sender, DependencyPropertyChangedEventArgs e)    {        this.ChangeVisualStateLocal();    }    /// <summary>    /// 内部调用切换视觉状态（默认不使用过渡）.    /// </summary>    private void ChangeVisualStateLocal()    {        this.ChangeVisualState(false);    }    /// <summary>    /// 尝试进入给定的视觉状态之一.    /// </summary>    /// <param name="useTransitions">是否使用过渡.</param>    /// <param name="stateNames">状态名称集合.</param>    private void GoToState(bool useTransitions, params string[] stateNames)    {        if (stateNames == null)        {            return;        }        foreach (string stateName in stateNames)        {            if (VisualStateManager.GoToState(this, stateName, useTransitions))            {                break;            }        }    }    /// <summary>    /// 访问键按下回调.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnAccessKeyPressed(object sender, AccessKeyPressedEventArgs e)    {        if (this.HasOwner && this.IsEnabled && !e.Handled && this.Owner != null)        {            this.Owner.IsUserInitiatedSelection = true;            this.IsSelected = true;            this.Owner.IsUserInitiatedSelection = false;            e.Handled = true;        }    }    /// <summary>    /// 固定属性更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnIsPinnedPropertyChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem)        {            BgTabControl? owner = tabItem.Owner;            if (owner != null && tabItem.Flags.IsLoaded && !tabItem.IsPinnedChangingInternally)            {                bool isPinnedValue = (bool)e.NewValue;                if (!owner.IsPinnedPropertyChangedSuccessfull(tabItem, isPinnedValue))                {                    tabItem.SetIsPinInternally(!isPinnedValue);                }            }        }    }    /// <summary>    /// 选项卡条位置属性更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnTabStripPlacementChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem)        {            tabItem.ChangeVisualStateLocal();            tabItem.UpdateTemplate();        }    }    /// <summary>    /// 选项卡方向属性更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnTabOrientationChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem)        {            if (tabItem.headerTabItemPresenter != null)            {                tabItem.headerTabItemPresenter.InvalidateMeasure();            }            tabItem.ChangeVisualStateLocal();        }    }    /// <summary>    /// 选中属性更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnIsSelectedPropertyChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem)        {            tabItem.OnIsSelectedChanged((bool)e.OldValue, (bool)e.NewValue);        }    }    /// <summary>    /// 换行属性更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnIsBreakChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem)        {            if (tabItem.Owner != null)            {                tabItem.Owner.RearrangeTabs();            }            tabItem.ChangeVisualStateLocal();        }    }    /// <summary>    /// 左模板更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnLeftTemplateChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem && tabItem.TabStripPlacement == Dock.Left)        {            tabItem.UpdateTemplate();        }    }    /// <summary>    /// 右模板更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnRightTemplateChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem && tabItem.TabStripPlacement == Dock.Right)        {            tabItem.UpdateTemplate();        }    }    /// <summary>    /// 上模板更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnTopTemplateChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem && tabItem.TabStripPlacement == Dock.Top)        {            tabItem.UpdateTemplate();        }    }    /// <summary>    /// 下模板更改回调.    /// </summary>    /// <param name="sender">依赖对象.</param>    /// <param name="e">参数.</param>    private static void OnBottomTemplateChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is BgTabItem tabItem && tabItem.TabStripPlacement == Dock.Bottom)        {            tabItem.UpdateTemplate();        }    }}